import { getSupabaseServerClientOptional } from "./supabase/server";

export async function getCurrentUser() {
  const supabase = await getSupabaseServerClientOptional();
  if (!supabase) return null;
  const { data } = await supabase.auth.getUser();
  return data?.user ?? null;
}

export async function isAdmin() {
  const supabase = await getSupabaseServerClientOptional();
  if (!supabase) return false;
  const userRes = await supabase.auth.getUser();
  const user = userRes.data?.user;
  if (!user) return false;
  const ADMIN_EMAIL = (process.env.NEXT_PUBLIC_ADMIN_EMAIL || process.env.ADMIN_EMAIL || "animeandmanga1810@gmail.com").toLowerCase();
  const userEmail = (user.email || "").toLowerCase();
  if (userEmail && ADMIN_EMAIL && userEmail === ADMIN_EMAIL) return true;
  const { data } = await supabase.from("profile").select("admin_user_id").limit(1).maybeSingle();
  const adminId = (data as any)?.admin_user_id as string | null;
  return !!adminId && adminId === user.id;
}
